import java.lang.reflect.Constructor;
import java.lang.reflect.Field;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVParserTest {

    private CSVParser csvParser;

    @BeforeEach
    public void setUp() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        Reader reader = new StringReader("header1,header2\nvalue1,value2");

        try {
            Constructor<CSVParser> constructor = CSVParser.class.getDeclaredConstructor(Reader.class, CSVFormat.class, long.class, long.class);
            constructor.setAccessible(true);
            csvParser = constructor.newInstance(reader, format, 0L, 42L);
        } catch (NoSuchMethodException e) {
            csvParser = new CSVParser(reader, format);
            Field recordNumberField = CSVParser.class.getDeclaredField("recordNumber");
            recordNumberField.setAccessible(true);
            recordNumberField.setLong(csvParser, 42L);
        }
    }

    @Test
    public void testGetRecordNumber() {
        long recordNumber = csvParser.getRecordNumber();
        assertEquals(42L, recordNumber);
    }
}
